@tailwind base;
@tailwind components;
@tailwind utilities;

@layer base {
  :root {
    --background: 0 0% 100%;
    --foreground: 222.2 84% 4.9%;
    --card: 0 0% 100%;
    --card-foreground: 222.2 84% 4.9%;
    --popover: 0 0% 100%;
    --popover-foreground: 222.2 84% 4.9%;
    --primary: 222.2 47.4% 11.2%;
    --primary-foreground: 210 40% 98%;
    --secondary: 210 40% 96.1%;
    --secondary-foreground: 222.2 47.4% 11.2%;
    --muted: 210 40% 96.1%;
    --muted-foreground: 215.4 16.3% 46.9%;
    --accent: 210 40% 96.1%;
    --accent-foreground: 222.2 47.4% 11.2%;
    --destructive: 0 84.2% 60.2%;
    --destructive-foreground: 210 40% 98%;
    --border: 214.3 31.8% 91.4%;
    --input: 214.3 31.8% 91.4%;
    --ring: 222.2 84% 4.9%;
    --radius: 0.5rem;
  }

  .dark {
    --background: 222.2 84% 4.9%;
    --foreground: 210 40% 98%;
    --card: 222.2 84% 4.9%;
    --card-foreground: 210 40% 98%;
    --popover: 222.2 84% 4.9%;
    --popover-foreground: 210 40% 98%;
    --primary: 210 40% 98%;
    --primary-foreground: 222.2 47.4% 11.2%;
    --secondary: 217.2 32.6% 17.5%;
    --secondary-foreground: 210 40% 98%;
    --muted: 217.2 32.6% 17.5%;
    --muted-foreground: 215 20.2% 65.1%;
    --accent: 217.2 32.6% 17.5%;
    --accent-foreground: 210 40% 98%;
    --destructive: 0 62.8% 30.6%;
    --destructive-foreground: 210 40% 98%;
    --border: 217.2 32.6% 17.5%;
    --input: 217.2 32.6% 17.5%;
    --ring: 212.7 26.8% 83.9%;
  }
}

body {
  @apply bg-background text-foreground;
}

.glass-panel {
  @apply bg-white/5 backdrop-blur-md border border-white/5;
}

import React, { useState } from 'react';
import { Project, User } from '../types';
import { Plus, Search, MoreVertical, Globe, Activity, TrendingUp, Calendar, ArrowRight, ShieldCheck, AlertCircle } from 'lucide-react';

interface ProjectsProps {
  onBack: () => void;
  onNavigateToAnalysis: () => void;
  user: User | null;
}

const Projects: React.FC<ProjectsProps> = ({ onBack, onNavigateToAnalysis, user }) => {
  const [searchTerm, setSearchTerm] = useState('');

  // Mock Data for Projects (simulating Database)
  const [projects] = useState<Project[]>([
    {
      id: '1',
      name: 'Mon Site Principal',
      domain: 'https://monsite.com',
      status: 'active',
      lastRun: new Date().toISOString(),
      visibilityScore: 65,
      trend: 12,
      nextRun: new Date(Date.now() + 86400000 * 7).toISOString()
    },
    {
      id: '2',
      name: 'Competitor Watch',
      domain: 'https://concurrent-direct.fr',
      status: 'active',
      lastRun: new Date(Date.now() - 86400000 * 3).toISOString(),
      visibilityScore: 42,
      trend: -5,
      nextRun: new Date(Date.now() + 86400000 * 4).toISOString()
    }
  ]);

  const canAddProject = (user?.plan === 'pro' && projects.length < 3) || (user?.plan === 'enterprise') || (user?.plan === 'free' && projects.length < 1);

  return (
    <div className="max-w-6xl mx-auto px-4 py-10 animate-in fade-in duration-500">

      {/* Header Section */}
      <div className="flex flex-col md:flex-row justify-between items-start md:items-center mb-10 gap-4">
        <div>
          <h1 className="text-3xl font-serif font-bold text-white mb-2">Mes Projets</h1>
          <p className="text-gray-400">Gérez vos sites et suivez leur performance AEO.</p>
        </div>
        <button 
          onClick={canAddProject ? onNavigateToAnalysis : () => alert("Limite de projets atteinte pour votre plan actuel.")}
          className={`flex items-center gap-2 px-6 py-3 rounded-xl font-bold transition-all ${
            canAddProject 
              ? 'bg-primary text-black hover:bg-primaryDark shadow-lg shadow-primary/20' 
              : 'bg-white/5 text-gray-500 cursor-not-allowed border border-white/10'
          }`}
        >
          <Plus size={18} />
          Nouveau Projet
        </button>
      </div>

      {/* Search & Filter Bar */}
      <div className="flex items-center gap-4 mb-8 bg-white/5 p-2 rounded-xl border border-white/10 w-full md:w-auto md:max-w-md">
        <Search className="text-gray-500 ml-2" size={20} />
        <input 
          type="text" 
          placeholder="Rechercher un domaine..." 
          className="bg-transparent border-none focus:ring-0 text-white w-full placeholder-gray-500"
          value={searchTerm}
          onChange={(e) => setSearchTerm(e.target.value)}
        />
      </div>

      {/* Projects Grid */}
      <div className="grid md:grid-cols-2 lg:grid-cols-3 gap-6">
        {projects.filter(p => p.name.toLowerCase().includes(searchTerm.toLowerCase())).map((project) => (
          <div key={project.id} className="glass-panel p-0 rounded-2xl border border-white/10 hover:border-primary/30 transition-all group overflow-hidden flex flex-col">

            {/* Card Header */}
            <div className="p-6 border-b border-white/5 bg-white/[0.02]">
              <div className="flex justify-between items-start mb-4">
                <div className="w-12 h-12 rounded-xl bg-gradient-to-br from-gray-800 to-black border border-white/10 flex items-center justify-center text-gray-300 font-bold text-xl shadow-inner">
                  {project.name.substring(0,2).toUpperCase()}
                </div>
                <div className="relative">
                  <button className="text-gray-500 hover:text-white transition-colors">
                    <MoreVertical size={20} />
                  </button>
                </div>
              </div>

              <h3 className="text-lg font-bold text-white mb-1 truncate">{project.name}</h3>
              <a href={project.domain} target="_blank" rel="noopener noreferrer" className="text-xs text-gray-500 hover:text-primary transition-colors flex items-center gap-1 mb-4">
                <Globe size={12} /> {project.domain}
              </a>

              <div className="flex items-center gap-2">
                <span className={`px-2 py-0.5 rounded text-[10px] font-bold uppercase tracking-wider border ${
                  project.status === 'active' 
                    ? 'bg-emerald-500/10 text-emerald-400 border-emerald-500/20' 
                    : 'bg-gray-500/10 text-gray-400 border-gray-500/20'
                }`}>
                  {project.status === 'active' ? 'Monitoring Actif' : 'En pause'}
                </span>
              </div>
            </div>

            {/* Card Stats */}
            <div className="p-6 flex-1 flex flex-col justify-end space-y-4">
              <div className="grid grid-cols-2 gap-4">
                <div className="bg-black/20 p-3 rounded-lg border border-white/5">
                  <p className="text-[10px] text-gray-500 uppercase mb-1">Score AEO</p>
                  <div className="flex items-end gap-2">
                    <span className="text-2xl font-bold text-white">{project.visibilityScore}</span>
                    <span className={`text-xs mb-1 font-medium flex items-center ${project.trend >= 0 ? 'text-emerald-400' : 'text-red-400'}`}>
                       {project.trend >= 0 ? '+' : ''}{project.trend}%
                       <TrendingUp size={12} className={`ml-0.5 ${project.trend < 0 ? 'rotate-180' : ''}`} />
                    </span>
                  </div>
                </div>
                <div className="bg-black/20 p-3 rounded-lg border border-white/5">
                   <p className="text-[10px] text-gray-500 uppercase mb-1">Dernier Scan</p>
                   <div className="flex items-center gap-1 h-full pb-1">
                      <Calendar size={14} className="text-gray-400" />
                      <span className="text-sm text-gray-300">
                        {new Date(project.lastRun || '').toLocaleDateString('fr-FR', {day:'numeric', month:'short'})}
                      </span>
                   </div>
                </div>
              </div>
            </div>

            {/* Card Actions */}
            <div className="p-4 bg-white/[0.02] border-t border-white/5 flex gap-2">
               <button 
                onClick={onNavigateToAnalysis}
                className="flex-1 py-2 rounded-lg bg-white/5 hover:bg-white/10 text-xs font-medium text-white transition-colors border border-white/5"
               >
                 Voir Rapport
               </button>
               <button className="px-3 py-2 rounded-lg bg-primary/10 hover:bg-primary/20 text-primary transition-colors border border-primary/20">
                 <Activity size={16} />
               </button>
            </div>

          </div>
        ))}

        {/* Add Project Card Placeholder */}
        {canAddProject && (
          <button 
            onClick={onNavigateToAnalysis}
            className="rounded-2xl border border-dashed border-white/10 bg-white/[0.01] hover:bg-white/[0.03] transition-all flex flex-col items-center justify-center p-8 gap-4 min-h-[300px] group"
          >
            <div className="w-16 h-16 rounded-full bg-white/5 flex items-center justify-center text-gray-500 group-hover:text-primary group-hover:bg-primary/10 transition-colors">
              <Plus size={32} />
            </div>
            <div className="text-center">
              <h3 className="text-lg font-medium text-gray-300 group-hover:text-white">Ajouter un projet</h3>
              <p className="text-sm text-gray-500 mt-1">Monitorez une nouvelle marque</p>
            </div>
          </button>
        )}
      </div>

      {!canAddProject && (
          <div className="mt-8 p-4 rounded-xl bg-amber-500/10 border border-amber-500/20 flex items-start gap-3">
              <AlertCircle className="text-amber-500 shrink-0 mt-0.5" size={20} />
              <div>
                  <h4 className="text-sm font-bold text-amber-200">Limite de plan atteinte</h4>
                  <p className="text-xs text-amber-200/70 mt-1">
                      Vous avez atteint la limite de projets pour votre plan actuel. Passez au plan Pro pour gérer jusqu'à 3 projets simultanément.
                  </p>
              </div>
          </div>
      )}
    </div>
  );
};

export default Projects;

