import React from 'react';
import ReactDOM from 'react-dom/client';
import App from './App';

const rootElement = document.getElementById('root');
if (!rootElement) {
  throw new Error("Could not find root element to mount to");
}

const root = ReactDOM.createRoot(rootElement);
root.render(
  <React.StrictMode>
    <App />
  </React.StrictMode>
);

import React, { useState } from 'react';
import { Mail, Lock, ArrowRight, Loader2, Github, AlertCircle, User as UserIcon, X, CheckCircle2 } from 'lucide-react';
import { User } from '../types';

interface LoginProps {
  onLogin: (user: User) => void;
  onBack: () => void;
}

const Login: React.FC<LoginProps> = ({ onLogin, onBack }) => {
  const [isRegistering, setIsRegistering] = useState(false);
  const [socialProvider, setSocialProvider] = useState<'google' | 'github' | null>(null);
  const [name, setName] = useState('');
  const [email, setEmail] = useState('');
  const [password, setPassword] = useState('');
  const [confirmPassword, setConfirmPassword] = useState('');
  const [isLoading, setIsLoading] = useState(false);
  const [error, setError] = useState('');

  // --- Handlers ---

  const initSocialLogin = (provider: 'google' | 'github') => {
    setSocialProvider(provider);
    setIsLoading(false);
  };

  const finalizeSocialLogin = async (provider: 'google' | 'github') => {
    setIsLoading(true);
    // Simulation délai réseau OAuth
    await new Promise(resolve => setTimeout(resolve, 1500));

    const mockUser: User = {
      id: `${provider}_${Math.random().toString(36).substr(2, 9)}`,
      name: provider === 'google' ? 'Utilisateur Google' : 'Développeur GitHub',
      email: provider === 'google' ? 'user@gmail.com' : 'dev@github.com',
      plan: 'free',
      credits: 15
    };

    onLogin(mockUser);
  };

  const handleSubmit = async (e: React.FormEvent) => {
    e.preventDefault();
    setError('');
    setIsLoading(true);

    // Simulation d'appel API
    await new Promise(resolve => setTimeout(resolve, 1500));

    // Validation simple
    if (!email || password.length < 4) {
      setError('Identifiants invalides. Le mot de passe doit contenir au moins 4 caractères.');
      setIsLoading(false);
      return;
    }

    if (isRegistering) {
        if (password !== confirmPassword) {
            setError("Les mots de passe ne correspondent pas.");
            setIsLoading(false);
            return;
        }
        if (!name) {
            setError("Veuillez renseigner votre nom.");
            setIsLoading(false);
            return;
        }
    }

    // Success Simulation
    const mockUser: User = {
      id: 'user_' + Math.random().toString(36).substr(2, 9),
      name: isRegistering ? name : email.split('@')[0],
      email: email,
      plan: 'free',
      credits: isRegistering ? 20 : 15
    };

    onLogin(mockUser);
  };

  const toggleMode = () => {
      setIsRegistering(!isRegistering);
      setError('');
      setPassword('');
      setConfirmPassword('');
  };

  // --- MOCK GOOGLE LOGIN VIEW ---
  if (socialProvider === 'google') {
    return (
      <div className="min-h-screen bg-white flex items-center justify-center font-sans text-gray-800 animate-in fade-in zoom-in duration-300">
        <div className="w-full max-w-[450px] p-8 md:border md:border-gray-200 md:rounded-lg md:shadow-sm bg-white">
          <div className="flex justify-center mb-4">
             <svg viewBox="0 0 24 24" className="w-10 h-10">
                <path d="M22.56 12.25c0-.78-.07-1.53-.2-2.25H12v4.26h5.92c-.26 1.37-1.04 2.53-2.21 3.31v2.77h3.57c2.08-1.92 3.28-4.74 3.28-8.09z" fill="#4285F4"/>
                <path d="M12 23c2.97 0 5.46-.98 7.28-2.66l-3.57-2.77c-.98.66-2.23 1.06-3.71 1.06-2.86 0-5.29-1.93-6.16-4.53H2.18v2.84C3.99 20.53 7.7 23 12 23z" fill="#34A853"/>
                <path d="M5.84 14.09c-.22-.66-.35-1.36-.35-2.09s.13-1.43.35-2.09V7.07H2.18C1.43 8.55 1 10.22 1 12s.43 3.45 1.18 4.93l2.85-2.22.81-.62z" fill="#FBBC05"/>
                <path d="M12 5.38c1.62 0 3.06.56 4.21 1.64l3.15-3.15C17.45 2.09 14.97 1 12 1 7.7 1 3.99 3.47 2.18 7.07l3.66 2.84c.87-2.6 3.3-4.53 6.16-4.53z" fill="#EA4335"/>
             </svg>
          </div>
          <h2 className="text-2xl font-medium text-center mb-2 text-gray-900">Connexion</h2>
          <p className="text-center text-gray-600 mb-8">Utiliser votre compte Google</p>

          <div className="space-y-6">
             <div className="relative group">
                <input 
                  type="email" 
                  className="peer w-full border border-gray-300 rounded px-3 py-3.5 text-gray-900 focus:border-blue-500 focus:ring-1 focus:ring-blue-500 outline-none transition-colors"
                  value="user@gmail.com" 
                  readOnly
                />
                <label className="absolute left-3 top-[-10px] bg-white px-1 text-xs text-blue-600 font-medium">Adresse e-mail</label>
             </div>

             <div className="text-sm text-blue-600 font-medium cursor-pointer hover:text-blue-700">
               Adresse e-mail oubliée ?
             </div>

             <div className="text-sm text-gray-600">
                Ce n'est pas votre ordinateur ? Utilisez le mode Invité pour vous connecter en privé. <span className="text-blue-600 font-medium cursor-pointer">En savoir plus</span>
             </div>

             <div className="flex justify-between items-center pt-8">
                <button 
                  onClick={() => setSocialProvider(null)}
                  className="text-blue-600 font-medium hover:bg-blue-50 px-4 py-2 rounded transition-colors"
                >
                  Créer un compte
                </button>
                <button 
                   onClick={() => finalizeSocialLogin('google')}
                   disabled={isLoading}
                   className="bg-[#1a73e8] text-white font-medium px-6 py-2 rounded hover:bg-blue-700 transition-colors shadow-sm min-w-[100px] flex justify-center"
                >
                   {isLoading ? <Loader2 size={20} className="animate-spin" /> : 'Suivant'}
                </button>
             </div>
          </div>
        </div>
        <div className="fixed bottom-4 left-4 text-xs text-gray-500 bg-gray-100 px-2 py-1 rounded border border-gray-300">
           Mode Simulation OAuth
        </div>
      </div>
    );
  }

  // --- MOCK GITHUB LOGIN VIEW ---
  if (socialProvider === 'github') {
    return (
      <div className="min-h-screen bg-[#0d1117] flex flex-col items-center pt-12 font-sans text-gray-100 animate-in fade-in zoom-in duration-300">
         <div className="mb-8">
            <Github size={48} className="text-white" />
         </div>
         <h2 className="text-xl font-light mb-4">Sign in to GitHub</h2>

         <div className="w-full max-w-[340px] bg-[#161b22] border border-[#30363d] rounded-lg p-5">
            <div className="space-y-4">
               <div>
                  <label className="block text-sm mb-2 font-medium">Username or email address</label>
                  <input 
                     type="text" 
                     className="w-full bg-[#0d1117] border border-[#30363d] rounded-md px-3 py-1.5 text-white focus:border-blue-500 focus:ring-2 focus:ring-blue-500/40 outline-none transition-all"
                     autoFocus
                  />
               </div>
               <div>
                  <div className="flex justify-between mb-2">
                     <label className="block text-sm font-medium">Password</label>
                     <span className="text-xs text-blue-400 hover:underline cursor-pointer">Forgot password?</span>
                  </div>
                  <input 
                     type="password" 
                     className="w-full bg-[#0d1117] border border-[#30363d] rounded-md px-3 py-1.5 text-white focus:border-blue-500 focus:ring-2 focus:ring-blue-500/40 outline-none transition-all"
                  />
               </div>

               <button 
                  onClick={() => finalizeSocialLogin('github')}
                  disabled={isLoading}
                  className="w-full bg-[#238636] hover:bg-[#2ea043] text-white font-bold py-1.5 rounded-md transition-colors border border-[rgba(240,246,252,0.1)] flex items-center justify-center gap-2"
               >
                  {isLoading ? <Loader2 size={16} className="animate-spin" /> : 'Sign in'}
               </button>
            </div>
         </div>

         <div className="mt-8 p-4 border border-[#30363d] rounded-lg text-sm flex gap-2">
            <span>New to GitHub?</span>
            <span className="text-blue-400 hover:underline cursor-pointer">Create an account</span>
         </div>

         <div className="mt-8 text-xs text-gray-500 flex gap-4">
             <span className="hover:text-blue-400 cursor-pointer">Terms</span>
             <span className="hover:text-blue-400 cursor-pointer">Privacy</span>
             <span className="hover:text-blue-400 cursor-pointer">Security</span>
             <button onClick={() => setSocialProvider(null)} className="hover:text-white underline">Cancel Simulation</button>
         </div>
      </div>
    );
  }

  // --- MAIN LOGIN VIEW ---
  return (
    <div className="min-h-[80vh] flex items-center justify-center px-4 relative animate-in fade-in zoom-in duration-500">

      {/* Background Decor */}
      <div className="absolute top-1/2 left-1/2 -translate-x-1/2 -translate-y-1/2 w-[500px] h-[500px] bg-primary/20 blur-[100px] rounded-full opacity-20 -z-10 pointer-events-none"></div>

      <div className="w-full max-w-md">
        <div className="glass-panel p-8 rounded-2xl border border-white/10 shadow-2xl relative overflow-hidden">

          {/* Header */}
          <div className="text-center mb-8">
            <div className="w-16 h-16 bg-gradient-to-br from-primary to-secondary rounded-2xl flex items-center justify-center text-black font-bold font-serif text-3xl mx-auto mb-6 shadow-lg shadow-primary/20">
              C
            </div>
            <h1 className="text-2xl font-serif font-bold text-white mb-2">
                {isRegistering ? 'Créer un compte' : 'Bon retour'}
            </h1>
            <p className="text-gray-400 text-sm">
                {isRegistering 
                    ? 'Rejoignez la première plateforme AEO.' 
                    : 'Connectez-vous pour accéder à votre dashboard.'}
            </p>
          </div>

          {/* Form */}
          <form onSubmit={handleSubmit} className="space-y-4">

            {error && (
              <div className="bg-red-500/10 border border-red-500/20 rounded-lg p-3 flex items-start gap-3 text-red-200 text-sm animate-in slide-in-from-top-2">
                <AlertCircle size={18} className="shrink-0 mt-0.5" />
                <span>{error}</span>
              </div>
            )}

            {isRegistering && (
                <div className="space-y-1.5 animate-in slide-in-from-left-2 duration-300">
                <label className="text-sm font-medium text-gray-300 ml-1">Nom complet</label>
                <div className="relative">
                    <UserIcon className="absolute left-3 top-1/2 -translate-y-1/2 text-gray-500" size={18} />
                    <input 
                    type="text" 
                    value={name}
                    onChange={(e) => setName(e.target.value)}
                    placeholder="Jean Dupont"
                    className="w-full bg-black/40 border border-white/10 rounded-xl py-3 pl-10 pr-4 text-white placeholder-gray-600 focus:border-primary/50 focus:ring-1 focus:ring-primary/50 transition-all outline-none"
                    required={isRegistering}
                    />
                </div>
                </div>
            )}

            <div className="space-y-1.5">
              <label className="text-sm font-medium text-gray-300 ml-1">Email professionnel</label>
              <div className="relative">
                <Mail className="absolute left-3 top-1/2 -translate-y-1/2 text-gray-500" size={18} />
                <input 
                  type="email" 
                  value={email}
                  onChange={(e) => setEmail(e.target.value)}
                  placeholder="nom@entreprise.com"
                  className="w-full bg-black/40 border border-white/10 rounded-xl py-3 pl-10 pr-4 text-white placeholder-gray-600 focus:border-primary/50 focus:ring-1 focus:ring-primary/50 transition-all outline-none"
                  required
                />
              </div>
            </div>

            <div className="space-y-1.5">
              <div className="flex justify-between items-center ml-1">
                <label className="text-sm font-medium text-gray-300">Mot de passe</label>
                {!isRegistering && (
                    <a href="#" className="text-xs text-primary hover:text-white transition-colors">Oublié ?</a>
                )}
              </div>
              <div className="relative">
                <Lock className="absolute left-3 top-1/2 -translate-y-1/2 text-gray-500" size={18} />
                <input 
                  type="password" 
                  value={password}
                  onChange={(e) => setPassword(e.target.value)}
                  placeholder="••••••••"
                  className="w-full bg-black/40 border border-white/10 rounded-xl py-3 pl-10 pr-4 text-white placeholder-gray-600 focus:border-primary/50 focus:ring-1 focus:ring-primary/50 transition-all outline-none"
                  required
                />
              </div>
            </div>

            {isRegistering && (
                <div className="space-y-1.5 animate-in slide-in-from-left-2 duration-300">
                <label className="text-sm font-medium text-gray-300 ml-1">Confirmer le mot de passe</label>
                <div className="relative">
                    <Lock className="absolute left-3 top-1/2 -translate-y-1/2 text-gray-500" size={18} />
                    <input 
                    type="password" 
                    value={confirmPassword}
                    onChange={(e) => setConfirmPassword(e.target.value)}
                    placeholder="••••••••"
                    className="w-full bg-black/40 border border-white/10 rounded-xl py-3 pl-10 pr-4 text-white placeholder-gray-600 focus:border-primary/50 focus:ring-1 focus:ring-primary/50 transition-all outline-none"
                    required={isRegistering}
                    />
                </div>
                </div>
            )}

            <button 
              type="submit" 
              disabled={isLoading}
              className="w-full bg-white text-black font-bold py-3.5 rounded-xl hover:bg-gray-200 transition-all transform active:scale-95 flex items-center justify-center gap-2 mt-2"
            >
              {isLoading ? <Loader2 size={20} className="animate-spin" /> : <>
                {isRegistering ? 'Créer mon compte' : 'Se connecter'} <ArrowRight size={18} />
              </>}
            </button>
          </form>

          {/* Social / Divider */}
          <div className="relative my-8">
            <div className="absolute inset-0 flex items-center">
              <div className="w-full border-t border-white/10"></div>
            </div>
            <div className="relative flex justify-center text-xs uppercase">
              <span className="bg-[#0f1115] px-2 text-gray-500">Ou continuer avec</span>
            </div>
          </div>

          <div className="grid grid-cols-2 gap-3">
             <button 
                type="button" 
                onClick={() => initSocialLogin('google')}
                className="flex items-center justify-center gap-2 py-2.5 bg-white/5 hover:bg-white/10 border border-white/10 rounded-lg transition-colors text-sm font-medium hover:border-primary/30"
             >
                <svg className="w-4 h-4" viewBox="0 0 24 24"><path d="M22.56 12.25c0-.78-.07-1.53-.2-2.25H12v4.26h5.92c-.26 1.37-1.04 2.53-2.21 3.31v2.77h3.57c2.08-1.92 3.28-4.74 3.28-8.09z" fill="#4285F4"/><path d="M12 23c2.97 0 5.46-.98 7.28-2.66l-3.57-2.77c-.98.66-2.23 1.06-3.71 1.06-2.86 0-5.29-1.93-6.16-4.53H2.18v2.84C3.99 20.53 7.7 23 12 23z" fill="#34A853"/><path d="M5.84 14.09c-.22-.66-.35-1.36-.35-2.09s.13-1.43.35-2.09V7.07H2.18C1.43 8.55 1 10.22 1 12s.43 3.45 1.18 4.93l2.85-2.22.81-.62z" fill="#FBBC05"/><path d="M12 5.38c1.62 0 3.06.56 4.21 1.64l3.15-3.15C17.45 2.09 14.97 1 12 1 7.7 1 3.99 3.47 2.18 7.07l3.66 2.84c.87-2.6 3.3-4.53 6.16-4.53z" fill="#EA4335"/></svg>
                Google
             </button>
             <button 
                type="button" 
                onClick={() => initSocialLogin('github')}
                className="flex items-center justify-center gap-2 py-2.5 bg-white/5 hover:bg-white/10 border border-white/10 rounded-lg transition-colors text-sm font-medium hover:border-primary/30"
             >
                <Github size={16} />
                GitHub
             </button>
          </div>

          <div className="mt-8 text-center">
             <p className="text-gray-400 text-sm">
               {isRegistering ? 'Déjà un compte ?' : 'Pas encore de compte ?'}
               <button onClick={toggleMode} className="text-primary hover:underline ml-1 font-medium">
                 {isRegistering ? 'Se connecter' : "S'inscrire"}
               </button>
             </p>
          </div>

        </div>

        <button onClick={onBack} className="w-full text-center mt-6 text-gray-500 hover:text-white text-sm transition-colors">
           Retour à l'accueil
        </button>
      </div>
    </div>
  );
};

export default Login;

import React, { useState } from 'react';
import { User, Activity, Globe, TrendingUp, ArrowLeft, Search, X, ChevronRight, BarChart3, Zap, CreditCard, Check, Download, Star } from 'lucide-react';
import { AnalysisResult } from '../types';

interface DashboardProps {
  onBack: () => void;
  history: AnalysisResult[];
  onView: (analysis: AnalysisResult) => void;
}

// Sub-component for the Prediction Chart
const PredictionChart: React.FC<{ hostname: string; baseScore: number }> = ({ hostname, baseScore }) => {
  return (
    <div className="bg-black/40 rounded-xl p-6 border border-white/5 mt-4 animate-in fade-in slide-in-from-top-4 duration-500">
      <div className="flex justify-between items-end mb-6">
        <div>
          <h4 className="text-lg font-serif font-bold text-white mb-1">Projection de Visibilité IA</h4>
          <p className="text-xs text-gray-400">Simulation sur 6 mois basée sur le score actuel ({baseScore}/100)</p>
        </div>
        <div className="flex gap-4 text-xs">
          <div className="flex items-center gap-2">
            <div className="w-3 h-3 rounded-full bg-gray-600"></div>
            <span className="text-gray-400">SEO Classique</span>
          </div>
          <div className="flex items-center gap-2">
            <div className="w-3 h-3 rounded-full bg-primary shadow-[0_0_8px_rgba(16,185,129,0.5)]"></div>
            <span className="text-primary font-medium">Avec CitedBy</span>
          </div>
        </div>
      </div>

      <div className="relative h-64 w-full bg-gradient-to-b from-white/5 to-transparent rounded-lg border border-white/10 p-4 overflow-hidden">
        {/* Grid Lines */}
        <div className="absolute inset-0 flex flex-col justify-between p-4 opacity-10 pointer-events-none">
          <div className="w-full h-px bg-white"></div>
          <div className="w-full h-px bg-white"></div>
          <div className="w-full h-px bg-white"></div>
          <div className="w-full h-px bg-white"></div>
          <div className="w-full h-px bg-white"></div>
        </div>

        <svg className="w-full h-full overflow-visible" preserveAspectRatio="none" viewBox="0 0 600 300">
          <defs>
            <linearGradient id={`grad-${hostname}`} x1="0" y1="0" x2="0" y2="1">
              <stop offset="0%" stopColor="#10b981" stopOpacity="0.4" />
              <stop offset="100%" stopColor="#10b981" stopOpacity="0" />
            </linearGradient>
          </defs>

          {/* Baseline (Standard SEO) - Flat/Slow growth */}
          <path 
            d="M0,250 C100,248 300,245 600,230" 
            fill="none" 
            stroke="#4b5563" 
            strokeWidth="2" 
            strokeDasharray="4,4"
          />

          {/* Predicted (CitedBy) - Exponential/S-Curve */}
          <path 
            d="M0,250 C150,250 250,150 600,50" 
            fill={`url(#grad-${hostname})`} 
            stroke="#10b981" 
            strokeWidth="3" 
            className="drop-shadow-[0_0_10px_rgba(16,185,129,0.4)]"
          />

          {/* Points */}
          <circle cx="0" cy="250" r="4" fill="#10b981" />
          <circle cx="600" cy="50" r="4" fill="#10b981" />

          {/* Annotations */}
          <text x="10" y="270" fill="#6b7280" fontSize="12">Aujourd'hui</text>
          <text x="590" y="270" fill="#6b7280" fontSize="12" textAnchor="end">M+6</text>

          <g transform="translate(450, 80)">
             <rect x="-10" y="-20" width="120" height="24" rx="4" fill="#064e3b" stroke="#10b981" strokeWidth="1" />
             <text x="50" y="-4" fill="white" fontSize="11" textAnchor="middle" fontWeight="bold">+450% Citations</text>
          </g>
        </svg>
      </div>

      <div className="mt-4 p-3 bg-white/5 rounded-lg border-l-2 border-primary">
        <p className="text-sm text-gray-300">
          <span className="text-primary font-bold">Analyse :</span> Pour <strong>{hostname}</strong>, l'indexation dans l'annuaire IA permettrait de passer d'une visibilité passive (liens bleus) à une recommandation active dans les réponses génératives.
        </p>
      </div>
    </div>
  );
};

const Dashboard: React.FC<DashboardProps> = ({ onBack, history, onView }) => {
  const [showDomainModal, setShowDomainModal] = useState(false);
  const [expandedDomain, setExpandedDomain] = useState<string | null>(null);

  // Calculate dynamic stats from history
  const totalAnalyses = history.length;

  const avgScore = totalAnalyses > 0 
    ? Math.round(history.reduce((acc, curr) => acc + curr.globalScore, 0) / totalAnalyses) 
    : 0;

  // Extract unique domains with their latest score
  const uniqueDomainsMap = new Map<string, AnalysisResult>();
  history.forEach(item => {
    const hostname = new URL(item.url).hostname;
    // Keep the most recent analysis for score reference
    if (!uniqueDomainsMap.has(hostname) || new Date(item.timestamp) > new Date(uniqueDomainsMap.get(hostname)!.timestamp)) {
      uniqueDomainsMap.set(hostname, item);
    }
  });
  const uniqueDomainsList = Array.from(uniqueDomainsMap.values());
  const uniqueDomainsCount = uniqueDomainsMap.size;

  const stats = [
    { 
      label: 'Analyses totales', 
      value: totalAnalyses.toString(), 
      icon: <Activity className="text-primary" />,
      action: null
    },
    { 
      label: 'Score Moyen', 
      value: totalAnalyses > 0 ? `${avgScore}/100` : '-', 
      icon: <TrendingUp className="text-accent" />,
      action: null
    },
    { 
      label: 'Domaines suivis', 
      value: uniqueDomainsCount.toString(), 
      icon: <Globe className="text-blue-400" />,
      action: () => setShowDomainModal(true),
      highlight: true
    },
  ];

  const formatDate = (isoString: string) => {
    const date = new Date(isoString);
    return new Intl.DateTimeFormat('fr-FR', {
      day: 'numeric',
      month: 'short',
      hour: '2-digit',
      minute: '2-digit'
    }).format(date);
  };

  return (
    <div className="max-w-6xl mx-auto px-4 py-10 relative">

      {/* DOMAIN MODAL */}
      {showDomainModal && (
        <div className="fixed inset-0 z-50 flex items-center justify-center p-4">
          <div className="absolute inset-0 bg-black/80 backdrop-blur-sm" onClick={() => setShowDomainModal(false)}></div>
          <div className="relative bg-[#0f1115] border border-white/10 rounded-2xl w-full max-w-3xl max-h-[85vh] flex flex-col shadow-2xl">

            <div className="p-6 border-b border-white/10 flex justify-between items-center bg-white/5">
              <div>
                <h2 className="text-2xl font-serif font-bold text-white">Portefeuille de Domaines</h2>
                <p className="text-sm text-gray-400">Analyse prédictive et suivi de performance par domaine.</p>
              </div>
              <button onClick={() => setShowDomainModal(false)} className="p-2 hover:bg-white/10 rounded-lg transition-colors">
                <X size={20} className="text-gray-400 hover:text-white" />
              </button>
            </div>

            <div className="p-6 overflow-y-auto custom-scrollbar">
              {uniqueDomainsList.length > 0 ? (
                <div className="space-y-4">
                  {uniqueDomainsList.map((domainData, i) => {
                    const hostname = new URL(domainData.url).hostname;
                    const isExpanded = expandedDomain === hostname;

                    return (
                      <div key={i} className={`border border-white/10 rounded-xl overflow-hidden transition-all ${isExpanded ? 'bg-white/5' : 'bg-transparent hover:bg-white/5'}`}>
                        <div 
                          className="p-4 flex items-center justify-between cursor-pointer"
                          onClick={() => setExpandedDomain(isExpanded ? null : hostname)}
                        >
                          <div className="flex items-center gap-4">
                             <div className="w-10 h-10 rounded-lg bg-primary/20 flex items-center justify-center text-primary font-bold">
                               {hostname.charAt(0).toUpperCase()}
                             </div>
                             <div>
                               <h3 className="font-medium text-white">{hostname}</h3>
                               <p className="text-xs text-gray-400">Dernier score : <span className={domainData.globalScore >= 70 ? 'text-emerald-400' : 'text-amber-400'}>{domainData.globalScore}/100</span></p>
                             </div>
                          </div>
                          <div className="flex items-center gap-3">
                             <span className="text-xs text-primary font-medium flex items-center gap-1 bg-primary/10 px-3 py-1 rounded-full border border-primary/20">
                                <BarChart3 size={12} />
                                {isExpanded ? 'Masquer' : 'Voir projection'}
                             </span>
                             <ChevronRight size={16} className={`text-gray-500 transition-transform ${isExpanded ? 'rotate-90' : ''}`} />
                          </div>
                        </div>

                        {isExpanded && (
                           <div className="px-4 pb-4 border-t border-white/10">
                              <PredictionChart hostname={hostname} baseScore={domainData.globalScore} />
                           </div>
                        )}
                      </div>
                    );
                  })}
                </div>
              ) : (
                <div className="text-center py-12 text-gray-500">
                  <Globe size={48} className="mx-auto mb-4 opacity-20" />
                  <p>Aucun domaine analysé pour le moment.</p>
                </div>
              )}
            </div>
          </div>
        </div>
      )}

      <button onClick={onBack} className="flex items-center text-gray-400 hover:text-white mb-6 transition-colors">
        <ArrowLeft size={18} className="mr-2" /> Retour au menu
      </button>

      <h1 className="text-3xl font-serif font-bold mb-8">Tableau de bord</h1>

      <div className="grid md:grid-cols-3 gap-6 mb-10">
        {stats.map((stat, i) => (
          <div 
            key={i} 
            className={`glass-panel p-6 rounded-xl flex items-center justify-between transition-all ${stat.highlight ? 'border-primary/50 shadow-[0_0_15px_rgba(16,185,129,0.1)] cursor-pointer hover:bg-white/10 group' : ''}`}
            onClick={stat.action || undefined}
          >
            <div>
              <p className="text-gray-400 text-sm mb-1 group-hover:text-white transition-colors">{stat.label}</p>
              <p className="text-2xl font-bold">{stat.value}</p>
              {stat.highlight && (
                <span className="text-xs text-primary mt-1 inline-flex items-center gap-1">
                  Voir projections <ChevronRight size={10} />
                </span>
              )}
            </div>
            <div className={`w-12 h-12 rounded-full flex items-center justify-center ${stat.highlight ? 'bg-primary/20 text-primary' : 'bg-white/5'}`}>
              {stat.icon}
            </div>
          </div>
        ))}
      </div>

      <div className="grid grid-cols-1 gap-8">

        {/* HISTORY TABLE (Full Width) */}
        <div>
           <div className="flex justify-between items-center mb-4">
             <h2 className="text-xl font-medium">Historique des analyses</h2>
           </div>

           <div className="glass-panel rounded-xl overflow-hidden min-h-[300px]">
             {history.length > 0 ? (
               <table className="w-full text-left">
                 <thead className="bg-white/5 text-gray-400 text-sm">
                   <tr>
                     <th className="p-4 font-medium">URL</th>
                     <th className="p-4 font-medium">Score</th>
                     <th className="p-4 font-medium">Date</th>
                     <th className="p-4 font-medium">Action</th>
                   </tr>
                 </thead>
                 <tbody className="divide-y divide-white/5">
                   {history.map((item, i) => (
                     <tr key={i} className="hover:bg-white/5 transition-colors">
                       <td className="p-4 truncate max-w-[300px] text-gray-300" title={item.url}>
                         {item.url}
                       </td>
                       <td className="p-4">
                          <span className={`font-bold ${item.globalScore >= 80 ? 'text-emerald-400' : item.globalScore >= 60 ? 'text-amber-400' : 'text-red-400'}`}>
                            {item.globalScore}
                          </span>
                       </td>
                       <td className="p-4 text-gray-500 text-sm">{formatDate(item.timestamp)}</td>
                       <td className="p-4">
                         <button 
                            onClick={() => onView(item)}
                            className="text-primary hover:underline text-sm font-medium"
                         >
                           Voir le rapport
                         </button>
                       </td>
                     </tr>
                   ))}
                 </tbody>
               </table>
             ) : (
                <div className="flex flex-col items-center justify-center h-full py-12 text-gray-500">
                  <Search size={48} className="mb-4 opacity-20" />
                  <p>Aucune analyse effectuée pour le moment.</p>
                  <button onClick={onBack} className="mt-4 text-primary hover:underline text-sm">
                    Lancer une nouvelle analyse
                  </button>
                </div>
             )}
           </div>
        </div>
      </div>
    </div>
  );
};

export default Dashboard;

import Link from "next/link";
import { 
  LayoutDashboard, 
  FolderOpen, 
  ScanLine, 
  Settings, 
  LogOut,
  CreditCard
} from "lucide-react";
import { createClient } from "@/lib/supabase/server";
import { redirect } from "next/navigation";

export default async function AppLayout({
  children,
}: {
  children: React.ReactNode;
}) {
  const supabase = createClient();
  const { data: { user } } = await supabase.auth.getUser();

  if (!user) {
    redirect('/login');
  }

  return (
    <div className="flex min-h-screen">
      {/* Sidebar */}
      <aside className="w-64 border-r border-white/10 bg-black/40 hidden md:flex flex-col sticky top-0 h-screen">
        <div className="p-6 border-b border-white/10">
          <div className="flex items-center gap-2 font-bold text-xl">
             <div className="w-8 h-8 rounded-lg bg-primary flex items-center justify-center text-black font-serif">C</div>
             CitedBy.ai
          </div>
        </div>

        <nav className="flex-1 p-4 space-y-2">
          <Link href="/app" className="flex items-center gap-3 px-4 py-3 rounded-lg hover:bg-white/5 text-gray-400 hover:text-white transition-colors">
            <LayoutDashboard size={20} />
            <span className="font-medium">Tableau de bord</span>
          </Link>
          <Link href="/app/projects" className="flex items-center gap-3 px-4 py-3 rounded-lg hover:bg-white/5 text-gray-400 hover:text-white transition-colors">
            <FolderOpen size={20} />
            <span className="font-medium">Projets</span>
          </Link>
          <div className="my-4 border-t border-white/5"></div>
          <Link href="/app/settings/billing" className="flex items-center gap-3 px-4 py-3 rounded-lg hover:bg-white/5 text-gray-400 hover:text-white transition-colors">
            <CreditCard size={20} />
            <span className="font-medium">Abonnement</span>
          </Link>
          <Link href="/app/settings" className="flex items-center gap-3 px-4 py-3 rounded-lg hover:bg-white/5 text-gray-400 hover:text-white transition-colors">
            <Settings size={20} />
            <span className="font-medium">Paramètres</span>
          </Link>
        </nav>

        <div className="p-4 border-t border-white/10">
          <div className="flex items-center gap-3 px-4 py-2">
            <div className="w-8 h-8 rounded-full bg-primary/20 flex items-center justify-center text-xs font-bold text-primary">
              {user.email?.[0].toUpperCase()}
            </div>
            <div className="overflow-hidden">
              <p className="text-sm font-medium truncate">{user.email}</p>
              <p className="text-xs text-gray-500">Plan Starter</p>
            </div>
          </div>
          <form action="/auth/signout" method="post">
            <button className="w-full mt-2 flex items-center gap-2 px-4 py-2 text-xs text-red-400 hover:text-red-300 transition-colors">
              <LogOut size={14} /> Déconnexion
            </button>
          </form>
        </div>
      </aside>

      {/* Main Content */}
      <main className="flex-1 overflow-y-auto">
        {children}
      </main>
    </div>
  );
}

