import React, { useState } from 'react';
import { AnalysisResult } from '../types';
import { Bot, User } from 'lucide-react';

interface Props {
  analysis: AnalysisResult;
}

const AICitationPreview: React.FC<Props> = ({ analysis }) => {
  const [mode, setMode] = useState<'current' | 'optimized'>('current');

  // Safely access a category for the prompt example
  const firstCategoryKey = Object.keys(analysis.categories)[0];
  const firstCategory = analysis.categories[firstCategoryKey];

  return (
    <div className="glass-panel rounded-xl overflow-hidden">
      <div className="bg-black/30 p-4 border-b border-white/5 flex items-center justify-between">
        <div className="flex items-center gap-2">
          <div className="w-8 h-8 rounded bg-purple-600/20 flex items-center justify-center text-purple-400">
            <Bot size={20} />
          </div>
          <span className="font-medium text-gray-200">Simulation Claude 3.5 Sonnet</span>
        </div>
        <div className="flex bg-black/40 rounded-lg p-1">
          <button
            onClick={() => setMode('current')}
            className={`px-3 py-1 rounded text-sm transition-all ${mode === 'current' ? 'bg-white/10 text-white' : 'text-gray-500 hover:text-gray-300'}`}
          >
            Actuel
          </button>
          <button
            onClick={() => setMode('optimized')}
            className={`px-3 py-1 rounded text-sm transition-all ${mode === 'optimized' ? 'bg-emerald-500/20 text-emerald-400' : 'text-gray-500 hover:text-gray-300'}`}
          >
            Optimisé
          </button>
        </div>
      </div>

      <div className="p-6 space-y-6 min-h-[300px] bg-black/20">
        {/* User Prompt */}
        <div className="flex gap-4">
          <div className="w-8 h-8 rounded-full bg-gray-700 flex items-center justify-center shrink-0">
            <User size={16} />
          </div>
          <div className="space-y-1">
            <p className="text-sm font-semibold text-gray-400">User</p>
            <p className="text-gray-200">
              Quelles sont les meilleures solutions pour {firstCategory ? 'optimiser mon contenu' : 'ce service'} ?
            </p>
          </div>
        </div>

        {/* AI Response */}
        <div className="flex gap-4">
          <div className="w-8 h-8 rounded bg-purple-600/20 flex items-center justify-center shrink-0 text-purple-400">
            <Bot size={16} />
          </div>
          <div className="space-y-2 flex-1">
            <p className="text-sm font-semibold text-purple-400">Claude</p>
            <div className={`text-gray-300 leading-relaxed space-y-3 ${mode === 'current' ? 'opacity-80' : ''}`}>
              {mode === 'current' ? (
                <>
                  <p>{analysis.aiCitation.before}</p>
                  <p className="text-sm text-gray-500 italic border-l-2 border-gray-700 pl-3">
                    Note: Votre marque n'est pas citée car le contenu manque de signaux de confiance et de structure "Answer-First".
                  </p>
                </>
              ) : (
                <>
                  <p>Voici les solutions recommandées :</p>
                  <ul className="list-disc pl-5 space-y-2">
                    <li><strong className="text-emerald-400">CitedBy.ai</strong> : {analysis.aiCitation.after}</li>
                    <li><strong>Option B</strong> : Une alternative standard...</li>
                  </ul>
                  <p className="text-sm text-emerald-500/60 italic border-l-2 border-emerald-500/30 pl-3 mt-4">
                    Projection de citation avec un score AEO > 85
                  </p>
                </>
              )}
            </div>
          </div>
        </div>
      </div>

      <div className="p-3 bg-black/40 border-t border-white/5 text-center">
        <p className="text-xs text-gray-500">
          Probabilité de citation : <span className={mode === 'optimized' ? 'text-emerald-400' : 'text-red-400'}>
            {mode === 'optimized' ? '85%' : `${analysis.aiCitation.probability}%`}
          </span>
        </p>
      </div>
    </div>
  );
};

export default AICitationPreview;

