// Check if Tailwind is loaded by checking computed styles
const body = document.body;
const cs = window.getComputedStyle(body);
JSON.stringify({
  bodyBg: cs.backgroundColor,
  bodyColor: cs.color,
  bodyClasses: body.className,
  stylesheetCount: document.styleSheets.length,
  linkTags: document.querySelectorAll('link[rel="stylesheet"]').length
});

// Check the actual CSS rules for bg-background
const sheets = document.styleSheets;
let found = [];
try {
  for (let s = 0; s < sheets.length; s++) {
    const rules = sheets[s].cssRules;
    for (let r = 0; r < Math.min(rules.length, 20); r++) {
      found.push(rules[r].cssText.substring(0, 120));
    }
  }
} catch(e) { found.push('Error: ' + e.message); }
JSON.stringify(found);

